// AUTO-GENERATED by workflow — ART ONLY (trap/hazard terrain sprites).
// File-body form (no import/export). All bindings provided by MEGA_HEADER.
// Pack: gen_hazard_art — ~8 procedural tile/hazard sprites under the hz_ prefix.
// The core code places + drives these; this file only defines their art.

// ---- local helpers (no external deps; mirror core tile look) ---------------
// Seamless floor base used by tile-style hazards so they blend with the dungeon
// floor. Mirrors core.js floorBase: flat tint + faint top bevel + grout lines.
function hzFloorBase(p, tint, tintLine) {
  p.rect(0, 0, 16, 16, tint);
  p.hline(0, 15, 0, lighten(tint, 0.08));
  p.hline(0, 15, 15, tintLine);
  p.vline(0, 15, 15, tintLine);
}
// scatter a few deterministic-ish specks for texture
function hzSpeck(p, x, y, c) { p.px(x, y, c); }

// ===========================================================================
// 1) hz_spikes — floor spike trap. Frame 0 retracted (flush plate w/ slots),
//    frame 1 extended (steel spikes thrust up). Tile-style, anchor [0,0].
// ===========================================================================
defineAnim('hz_spikes', 16, 16, 2, (p, f) => {
  // stone base plate set into the floor
  hzFloorBase(p, P.floor2, P.floorLine);
  p.rect(1, 1, 14, 14, darken(P.floor2, 0.18));
  p.rect(2, 2, 12, 12, P.floor2);
  p.rectLine(2, 2, 12, 12, darken(P.floor2, 0.3));
  // four slot holes the spikes emerge from (always visible)
  const slots = [[3, 4], [8, 4], [3, 9], [8, 9]];
  for (const [sx, sy] of slots) { p.rect(sx, sy, 2, 3, P.shadow); }
  if (f === 0) {
    // retracted: just a hint of metal at the bottom of each slot
    for (const [sx, sy] of slots) { p.hline(sx, sx + 1, sy + 2, P.steelD); }
  } else {
    // extended: triangular steel spikes rising from each slot
    for (const [sx, sy] of slots) {
      const cx = sx + 1;
      for (let k = 0; k < 4; k++) {
        const w = (3 - k) * 0.5;
        p.hline(cx - w, cx + w, sy + 3 - k - 1, k === 0 ? P.steel : (k < 2 ? P.steelL : P.white));
      }
      p.px(cx, sy - 1, P.white);            // sharp tip glint
      p.vline(sy - 1, sy + 1, cx + 1, P.steelD); // shaded side
    }
  }
}, { anchor: [0, 0], fps: 4 });

// ===========================================================================
// 2) hz_lava — bubbling lava pool. Animated molten surface w/ glowing cracks
//    and rising bubbles. Tile-style, anchor [0,0], fills the full tile.
// ===========================================================================
defineAnim('hz_lava', 16, 16, 4, (p, f) => {
  // dark crusted rim then molten interior
  p.rect(0, 0, 16, 16, darken(P.redD, 0.5));
  p.rect(1, 1, 14, 14, P.blood);
  p.rect(2, 2, 12, 12, P.redD);
  p.rect(3, 3, 10, 10, darken(P.ember, 0.18));
  // glowing molten veins (shift each frame for a flowing feel)
  const o = f;
  p.line(3, 5 + (o % 2), 7, 8, P.ember);
  p.line(7, 8, 12, 6 + ((o + 1) % 2), P.ember);
  p.line(4, 11, 9, 10 - (o % 2), P.emberL);
  p.line(9, 10, 13, 12, P.ember);
  // rising bubbles: positions cycle through the 4 frames
  const bubbles = [[5, 9], [10, 7], [7, 12], [11, 11]];
  const b = bubbles[f % 4];
  p.ellipse(b[0], b[1], 1.6, 1.6, P.emberL);
  p.px(b[0], b[1] - 1, P.white);
  const b2 = bubbles[(f + 2) % 4];
  p.px(b2[0], b2[1], P.emberL);
  // a couple of cooled black crust islands
  hzSpeck(p, 6, 4, darken(P.blood, 0.3));
  hzSpeck(p, 12, 9, darken(P.blood, 0.3));
}, { anchor: [0, 0], fps: 5 });

// ===========================================================================
// 3) hz_caltrops — scattered iron caltrops on the floor. Static tile.
// ===========================================================================
defineSprite('hz_caltrops', 16, 16, (p) => {
  hzFloorBase(p, P.floor, P.floorLine);
  hzSpeck(p, 4, 5, P.floor2); hzSpeck(p, 12, 11, darken(P.floor, 0.2));
  // a single 4-spike caltrop primitive
  const caltrop = (cx, cy) => {
    p.line(cx, cy, cx - 2, cy - 2, P.steel);
    p.line(cx, cy, cx + 2, cy - 2, P.steel);
    p.line(cx, cy, cx, cy - 3, P.steelL);
    p.line(cx, cy, cx - 1, cy + 1, P.steelD);
    p.px(cx, cy, P.iron);
    p.px(cx, cy - 3, P.white);              // top point glint
    p.px(cx - 2, cy - 2, P.white); p.px(cx + 2, cy - 2, P.white);
  };
  caltrop(5, 7); caltrop(11, 6); caltrop(8, 12); caltrop(13, 12);
  p.outline(P.ink);                          // crisp the metal against floor
}, { anchor: [0, 0] });

// ===========================================================================
// 4) hz_thorns — a writhing thorn bramble patch. Static tile.
// ===========================================================================
defineSprite('hz_thorns', 16, 16, (p) => {
  hzFloorBase(p, P.floor, P.floorLine);
  // tangled vines (dark green) snaking across the tile
  p.line(1, 13, 5, 9, P.greenD);
  p.line(5, 9, 9, 12, P.greenD);
  p.line(9, 12, 14, 8, P.greenD);
  p.line(2, 5, 6, 7, P.poisonD);
  p.line(6, 7, 10, 4, P.poisonD);
  p.line(10, 4, 14, 6, P.poisonD);
  p.line(7, 14, 8, 8, P.greenD);
  // sharp thorns jutting off the vines
  const thorn = (x, y, dx, dy, c) => { p.px(x, y, c); p.px(x + dx, y + dy, lighten(c, 0.25)); };
  thorn(5, 9, -1, -1, P.greenL); thorn(9, 12, 1, -1, P.greenL);
  thorn(6, 7, 0, -1, P.poison); thorn(10, 4, 1, -1, P.poison);
  thorn(3, 11, -1, 0, P.greenL); thorn(12, 7, 1, -1, P.poison);
  thorn(8, 10, 0, -1, P.greenL);
  // a few menacing red thorn tips
  p.px(2, 5, P.red); p.px(14, 8, P.redL); p.px(8, 8, P.red);
  p.outline(P.ink);
}, { anchor: [0, 0] });

// ===========================================================================
// 5) hz_poisonpool — animated bubbling toxic sludge pool. Tile-style.
// ===========================================================================
defineAnim('hz_poisonpool', 16, 16, 4, (p, f) => {
  // dark toxic rim then sickly green interior
  p.rect(0, 0, 16, 16, darken(P.poisonD, 0.45));
  p.rect(1, 1, 14, 14, P.poisonD);
  p.rect(2, 2, 12, 12, mix(P.poisonD, P.poison, 0.5));
  p.rect(3, 3, 10, 10, darken(P.poison, 0.15));
  // drifting toxic swirls
  const o = f;
  p.line(3, 6 + (o % 2), 8, 5, P.poison);
  p.line(8, 9, 13, 10 - (o % 2), P.poison);
  p.line(4, 11, 10, 12, P.poisonD);
  // bubbling pockets cycling through frames
  const bubbles = [[6, 8], [11, 6], [8, 11], [5, 12]];
  const b = bubbles[f % 4];
  p.ellipse(b[0], b[1], 1.7, 1.7, P.toxic);
  p.px(b[0], b[1] - 1, P.greenL);
  const b2 = bubbles[(f + 2) % 4];
  p.px(b2[0], b2[1], P.toxic);
  // settled gunk specks
  hzSpeck(p, 7, 4, darken(P.poisonD, 0.25));
  hzSpeck(p, 12, 11, darken(P.poisonD, 0.25));
}, { anchor: [0, 0], fps: 4 });

// ===========================================================================
// 6) hz_firejet — a vertical flame jet vent. 12x16, feet-anchored at [6,15]
//    so the core can stand it on a floor tile. Animated licking flame.
// ===========================================================================
defineAnim('hz_firejet', 12, 16, 4, (p, f) => {
  // metal vent nozzle at the base
  p.rect(3, 13, 6, 3, P.steelD);
  p.rect(4, 13, 4, 1, P.steel);
  p.rect(4, 14, 4, 2, P.iron);
  p.px(4, 15, P.gray2); p.px(7, 15, P.gray2);
  // flame column: height + sway driven by frame
  const sway = [0, 1, 0, -1][f];
  const ht = [9, 11, 10, 12][f];           // flame top row (smaller = taller)
  const topY = 13 - ht;
  for (let y = 13; y >= topY; y--) {
    const t = (13 - y) / ht;                // 0 base .. 1 tip
    const w = (1 - t) * 3.2 + 0.6;          // taper toward the tip
    const cx = 6 + sway * t;                // lean more near the tip
    // outer / mid / core colour bands
    const outer = t < 0.7 ? P.ember : P.red;
    p.hline(cx - w, cx + w, y, outer);
    if (w > 1.2) p.hline(cx - w + 1, cx + w - 1, y, P.emberL);
    if (w > 1.8 && t < 0.6) p.hline(cx - 0.6, cx + 0.6, y, P.white);
  }
  // a couple of detached spark embers above the tip
  p.px(6 + sway, topY - 1, P.emberL);
  if (f % 2 === 0) p.px(6 + sway + 1, topY - 2, P.ember);
  p.outline(P.ink);
}, { anchor: [6, 15], fps: 9 });

// ===========================================================================
// 7) hz_rune — a glowing arcane trap rune etched into the floor. Tile-style.
//    Pulsing magic circle + sigil (single static frame, core can fade alpha).
// ===========================================================================
defineSprite('hz_rune', 16, 16, (p) => {
  hzFloorBase(p, P.floor, P.floorLine);
  hzSpeck(p, 3, 12, P.floor2); hzSpeck(p, 13, 4, darken(P.floor, 0.2));
  // outer + inner glowing rings
  p.ring(8, 8, 6, P.purpleD);
  p.ring(8, 8, 6, P.purple);
  p.ring(8, 8, 4, P.mana);
  p.ring(8, 8, 4, P.manaL);
  // tick marks around the outer ring (cardinal points)
  p.px(8, 1, P.manaL); p.px(8, 14, P.manaL); p.px(1, 8, P.manaL); p.px(14, 8, P.manaL);
  // central sigil: a triangle + dot
  p.line(8, 4, 5, 10, P.manaL);
  p.line(8, 4, 11, 10, P.manaL);
  p.line(5, 10, 11, 10, P.manaL);
  p.ellipse(8, 8, 1.2, 1.2, P.white);
  p.px(8, 8, P.manaL);
  // arcane glow accents
  p.px(5, 5, P.purpleL); p.px(11, 5, P.purpleL); p.px(8, 12, P.purpleL);
}, { anchor: [0, 0] });

// ===========================================================================
// 8) hz_crack — a collapsing/cracked floor tile (fragile, about to give way).
//    Tile-style; jagged fissures with a dark void peeking through.
// ===========================================================================
defineSprite('hz_crack', 16, 16, (p) => {
  hzFloorBase(p, P.floor, P.floorLine);
  // big branching fissure network
  p.line(2, 1, 6, 6, P.shadow);
  p.line(6, 6, 5, 11, P.shadow);
  p.line(6, 6, 11, 8, P.shadow);
  p.line(11, 8, 14, 14, P.shadow);
  p.line(11, 8, 15, 5, P.shadow);
  p.line(5, 11, 8, 15, P.shadow);
  // widen the main cracks one px (dark void underneath)
  p.px(6, 7, P.shadow); p.px(7, 6, P.shadow); p.px(10, 8, P.shadow); p.px(5, 9, P.shadow);
  // crumbling edges + loose rubble chips around the cracks
  p.px(5, 5, darken(P.floor, 0.3)); p.px(7, 7, darken(P.floor, 0.3));
  p.px(11, 9, darken(P.floor, 0.3)); p.px(12, 11, darken(P.floor, 0.3));
  p.px(4, 10, P.floor2); p.px(9, 9, P.floor2); p.px(13, 6, P.floor2);
  // faint highlight lip on a couple of broken edges to read as depth
  p.px(6, 5, P.floor2); p.px(10, 7, P.floor2);
}, { anchor: [0, 0] });
